  --jb-checkbox-checked-border-invalid: var(--jb-blue-4);
  --jb-checkbox-checked-ring-invalid: var(--jb-red-4);
  --jb-checkbox-checked-bg-disabled: var(--jb-gray-9);
  --jb-checkbox-checked-border-disabled: var(--jb-gray-9);
