  --jb-checkbox-indeterminate-border-hover: var(--jb-blue-3);
  --jb-checkbox-indeterminate-bg-active: var(--jb-blue-2);
  --jb-checkbox-indeterminate-border-active: var(--jb-blue-2);
  --jb-checkbox-indeterminate-ring: var(--jb-blue-4);
  --jb-checkbox-indeterminate-border-invalid: var(--jb-blue-4);
  --jb-checkbox-indeterminate-ring-invalid: var(--jb-red-4);
  --jb-checkbox-indeterminate-bg-disabled: var(--jb-gray-9);
